{"code": "import urllib.request
import json
from datetime import datetime

# 搜索免费 Token 提供商
providers = [
    ("OpenAI API Keys", "https://github.com/fate-zero/openai-api-keys"),
    ("FreeGPT3.5", "https://github.com/Llhaz2/freegpt35"),
    ("PlusGPT", "https://github.com/chatanywhere/GPT_API_v2"),
    ("Free-ChatGPT", "https://github.com/chatanywhere/GPT_API_v2"),
]

results = []
for name, url in providers:
    try:
        # 尝试获取 GitHub 仓库信息
        api_url = url.replace("https://github.com/", "https://api.github.com/repos/")
        req = urllib.request.Request(api_url, headers={
            'User-Agent': 'Hermes-Agent/1.0',
            'Accept': 'application/vnd.github.v3+json'
        })
        with urllib.request.urlopen(req, timeout=5) as resp:
            data = json.loads(resp.read().decode())
            stars = data.get('stargazers_count', 0)
            updated = data.get('updated_at', 'N/A')
            results.append({
                "name": name,
                "url": url,
                "stars": stars,
                "updated": updated
            })
    except Exception as e:
        results.append({
            "name": name,
            "url": url,
            "error": str(e)
        })

print(f"Free Token Providers ({datetime.now().strftime('%Y-%m-%d')}):")
print("=" * 80)
for r in results:
    print(f"• {r['name']}")
    print(f"  URL: {r['url']}")
    if 'stars' in r:
        print(f"  ⭐ {r['stars']} stars | Updated: {r['updated']}")
    else:
        print(f"  ❌ {r['error']}")
    print()
